begin;
create table if not exists public.development_commercial_releases(id uuid primary key default gen_random_uuid(),organization_id uuid not null references public.organizations(id) on delete cascade,development_id uuid not null references public.developments(id) on delete cascade,version integer not null,title text not null,price_table_material_id uuid not null references public.project_materials(id),sales_mirror_material_id uuid references public.project_materials(id),inventory_import_batch_id uuid references public.inventory_import_batches(id),payment_rule_id uuid not null references public.developer_payment_flow_rules(id),valid_from timestamptz not null,valid_until timestamptz,status text not null default 'draft' check(status in('draft','active','superseded','expired','revoked')),notes text,created_by uuid not null references public.profiles(id),approved_by uuid references public.profiles(id),created_at timestamptz not null default now(),approved_at timestamptz,revoked_at timestamptz,check(valid_until is null or valid_until>valid_from),check(sales_mirror_material_id is not null or inventory_import_batch_id is not null),unique(organization_id,development_id,version));
create unique index if not exists commercial_release_one_active_idx on public.development_commercial_releases(organization_id,development_id)where status='active';create index if not exists commercial_release_validity_idx on public.development_commercial_releases(organization_id,development_id,status,valid_from,valid_until);
create table if not exists public.commercial_release_events(id uuid primary key default gen_random_uuid(),organization_id uuid not null references public.organizations(id) on delete cascade,development_id uuid not null references public.developments(id) on delete cascade,release_id uuid not null references public.development_commercial_releases(id) on delete cascade,actor_id uuid not null references public.profiles(id),event_type text not null check(event_type in('created','activated','superseded','revoked','expired')),reason text not null check(char_length(reason) between 10 and 500),created_at timestamptz not null default now());
alter table public.development_commercial_releases enable row level security;alter table public.commercial_release_events enable row level security;drop policy if exists development_commercial_releases_scope on public.development_commercial_releases;create policy development_commercial_releases_scope on public.development_commercial_releases for select to authenticated using(organization_id=(select public.current_organization_id()));drop policy if exists commercial_release_events_scope on public.commercial_release_events;create policy commercial_release_events_scope on public.commercial_release_events for select to authenticated using(organization_id=(select public.current_organization_id()));revoke all on public.development_commercial_releases,public.commercial_release_events from anon;revoke insert,update,delete on public.development_commercial_releases,public.commercial_release_events from authenticated;grant select on public.development_commercial_releases,public.commercial_release_events to authenticated;
alter table public.commercial_simulations add column if not exists commercial_release_id uuid references public.development_commercial_releases(id) on delete restrict;
create or replace function public.create_commercial_release_draft(p_actor_id uuid,p_organization_id uuid,p_development_id uuid,p_title text,p_price_table_material_id uuid,p_sales_mirror_material_id uuid,p_inventory_import_batch_id uuid,p_payment_rule_id uuid,p_valid_from timestamptz,p_valid_until timestamptz,p_notes text)returns jsonb language plpgsql security definer set search_path='' as $$
declare actor_role text;next_version integer;target public.development_commercial_releases;project_developer_name text;
begin select coalesce(commercial_role,case role when'admin'then'director'else role end)into actor_role from public.profiles where id=p_actor_id and organization_id=p_organization_id and active=true;if actor_role not in('director','superintendent')then raise exception 'commercial_release_actor_forbidden';end if;if char_length(trim(coalesce(p_title,'')))<3 or p_valid_from is null or p_valid_until is not null and p_valid_until<=p_valid_from then raise exception 'commercial_release_validity_invalid';end if;select d.developer_name into project_developer_name from public.developments d where d.id=p_development_id and d.organization_id=p_organization_id;if project_developer_name is null then raise exception 'commercial_release_development_invalid';end if;if not exists(select 1 from public.project_materials m where m.id=p_price_table_material_id and m.organization_id=p_organization_id and m.development_id=p_development_id and m.material_type='price_table'and(m.valid_from is null or m.valid_from<=p_valid_from::date)and(m.valid_until is null or(p_valid_until is not null and m.valid_until>=p_valid_until::date)))then raise exception 'commercial_release_price_table_invalid';end if;if p_sales_mirror_material_id is not null and not exists(select 1 from public.project_materials m where m.id=p_sales_mirror_material_id and m.organization_id=p_organization_id and m.development_id=p_development_id and m.material_type='sales_mirror'and(m.valid_from is null or m.valid_from<=p_valid_from::date)and(m.valid_until is null or(p_valid_until is not null and m.valid_until>=p_valid_until::date)))then raise exception 'commercial_release_mirror_invalid';end if;if p_inventory_import_batch_id is not null and not exists(select 1 from public.inventory_import_batches where id=p_inventory_import_batch_id and organization_id=p_organization_id and development_id=p_development_id and status='applied')then raise exception 'commercial_release_import_invalid';end if;if not exists(select 1 from public.developer_payment_flow_rules r where r.id=p_payment_rule_id and r.organization_id=p_organization_id and lower(trim(r.developer_name))=lower(trim(project_developer_name))and(r.valid_from is null or r.valid_from<=p_valid_from::date)and(r.valid_until is null or(p_valid_until is not null and r.valid_until>=p_valid_until::date)))then raise exception 'commercial_release_payment_rule_invalid';end if;select coalesce(max(version),0)+1 into next_version from public.development_commercial_releases where organization_id=p_organization_id and development_id=p_development_id for update;
 insert into public.development_commercial_releases(organization_id,development_id,version,title,price_table_material_id,sales_mirror_material_id,inventory_import_batch_id,payment_rule_id,valid_from,valid_until,notes,created_by)values(p_organization_id,p_development_id,next_version,trim(p_title),p_price_table_material_id,p_sales_mirror_material_id,p_inventory_import_batch_id,p_payment_rule_id,p_valid_from,p_valid_until,nullif(trim(p_notes),''),p_actor_id)returning * into target;insert into public.commercial_release_events(organization_id,development_id,release_id,actor_id,event_type,reason)values(p_organization_id,p_development_id,target.id,p_actor_id,'created','Rascunho comercial criado para revisão');return jsonb_build_object('release',to_jsonb(target),'singleActiveRelease',true,'snapshotRequired',true,'auditable',true);end $$;
create or replace function public.activate_commercial_release(p_actor_id uuid,p_organization_id uuid,p_release_id uuid,p_reason text)returns jsonb language plpgsql security definer set search_path='' as $$
declare actor_role text;target public.development_commercial_releases;previous_id uuid;
begin select coalesce(commercial_role,case role when'admin'then'director'else role end)into actor_role from public.profiles where id=p_actor_id and organization_id=p_organization_id and active=true;if actor_role<>'director'then raise exception 'commercial_release_director_required';end if;if char_length(trim(coalesce(p_reason,'')))<10 then raise exception 'commercial_release_reason_required';end if;select * into target from public.development_commercial_releases where id=p_release_id and organization_id=p_organization_id and status='draft'for update;if target.id is null then raise exception 'commercial_release_unavailable';end if;if target.valid_from>now()then raise exception 'commercial_release_not_started';end if;if target.valid_until is not null and target.valid_until<=now()then raise exception 'commercial_release_expired';end if;select id into previous_id from public.development_commercial_releases where organization_id=p_organization_id and development_id=target.development_id and status='active'for update;update public.development_commercial_releases set status='superseded'where id=previous_id;update public.development_commercial_releases set status='active',approved_by=p_actor_id,approved_at=now()where id=target.id;update public.project_materials set is_current=(id in(target.price_table_material_id,target.sales_mirror_material_id))where organization_id=p_organization_id and development_id=target.development_id and material_type in('price_table','sales_mirror');update public.developer_payment_flow_rules set active=(id=target.payment_rule_id)where organization_id=p_organization_id and lower(developer_name)=(select lower(d.developer_name)from public.developments d where d.id=target.development_id);
 if previous_id is not null then insert into public.commercial_release_events(organization_id,development_id,release_id,actor_id,event_type,reason)values(p_organization_id,target.development_id,previous_id,p_actor_id,'superseded',trim(p_reason));end if;insert into public.commercial_release_events(organization_id,development_id,release_id,actor_id,event_type,reason)values(p_organization_id,target.development_id,target.id,p_actor_id,'activated',trim(p_reason));return jsonb_build_object('releaseId',target.id,'version',target.version,'status','active','previousReleaseId',previous_id,'singleActiveRelease',true,'directorApproved',true,'auditable',true);end $$;
revoke all on function public.create_commercial_release_draft(uuid,uuid,uuid,text,uuid,uuid,uuid,uuid,timestamptz,timestamptz,text)from public,anon,authenticated;grant execute on function public.create_commercial_release_draft(uuid,uuid,uuid,text,uuid,uuid,uuid,uuid,timestamptz,timestamptz,text)to service_role;revoke all on function public.activate_commercial_release(uuid,uuid,uuid,text)from public,anon,authenticated;grant execute on function public.activate_commercial_release(uuid,uuid,uuid,text)to service_role;
commit;
